sql:
SELECT total_area_x
FROM statistics_x
WHERE created_at BETWEEN '2023-05-01 00:00:00' AND '2023-05-02 23:59:59';

SELECT COUNT(*) AS total_statistics
FROM (
    SELECT statistic_id FROM statistics_x
    UNION ALL
    SELECT statistic_id FROM statistics_y
) AS combined_statistics;

SELECT MAX(max_area) AS max_dataset_area
FROM (
    SELECT max_area FROM statistics_x
    UNION ALL
    SELECT max_area FROM statistics_y
) AS combined_areas;

SELECT AVG(jaccard_similarity) AS average_jaccard_similarity
FROM similarities
WHERE created_at BETWEEN '2023-01-01' AND '2023-12-31';

